"use strict";var numericRegularExpression=/^[0-9,.]+$/,commaRegularExpression=/,/g,addReplaceCommaToDotListener=function(){$('form[name="product_edit"] input[type="text"]').each((function(){this.addEventListener("keyup",replaceCommaToDot)}))},replaceCommaToDot=function(){var e=$(this).val();null!==e.match(numericRegularExpression)&&null!==e.match(commaRegularExpression)&&(e=e.replace(commaRegularExpression,"."),$(this).val(e))};"loading"===document.readyState?document.addEventListener("DOMContentLoaded",addReplaceCommaToDotListener):addReplaceCommaToDotListener();